function suggestMovementPurpose(name) {
  if (!name || name.length < 2) return "";
  const n = name.toLowerCase();
  for (const rule of PURPOSE_MAP) {
    if (rule.keys.some(k => n.includes(k.toLowerCase()))) return rule.purpose;
  }
  return "";
}

