  async function handleLogin(email, pw, options = {}) {
    setLoading(true);
    setLoginErr("");
    try {
      const keepLogin = memberMode ? options.keepLogin !== false : true;
      await setPersistence(auth, keepLogin ? browserLocalPersistence : browserSessionPersistence);
      saveKeepLogin(keepLogin);
      await signInWithEmailAndPassword(auth, email.trim().toLowerCase(), pw);
    }
    catch(e) { const code=e?.code||""; setLoginErr(memberMode&&code==="auth/user-not-found" ? "회원 이메일은 저장되어 있지만 Firebase Authentication 계정이 없습니다. 대표에게 회원앱 초대 발송을 요청해주세요." : "로그인 실패: 이메일 또는 비밀번호를 확인해주세요."); }
    finally { setLoading(false); }
  }

  async function handleLogout() {
    await signOut(auth);
    setScreen("home");
    setMember(null);
    // 같은 브라우저를 여러 트레이너가 함께 쓰는 경우를 대비해 로그아웃 시 이전 계정의
    // 회원 목록·세션·2:1 수업 캐시를 전부 비운다 — 다음 로그인 계정에게 이전 계정 데이터가
    // 잠깐이라도 보이는 일이 없도록 함(관리자 화면 재검증은 verifiedAdminUid 가드가 별도로 처리).
    setMembers([]);
    setSessionsMap({});
    setSessions([]);
    setBodyData(null);
    setNutritionData(null);
    setMemberPrivateData(null);
    setPairSessions([]);
    setEditPairSession(null);
    setEditSess(null);
  }

  const [migrating, setMigrating] = useState(false);


  async function handleMigrate() {
    if (!window.confirm(
      "기존 회원에 trainerUid를 추가합니다.\n" +
      "이미 설정된 회원은 건드리지 않습니다.\n\n" +
      "계속하시겠습니까?"
    )) return;
    setMigrating(true);
    try {
      const result = await migrateAddTrainerUid();
      if (result.count === 0 && result.skipped > 0) {
        showToast(`모든 회원(${result.skipped}명) 이미 정상 상태 ✓`);
      } else if (result.count > 0) {
        showToast(`${result.count}명 업데이트 완료 ✓`);
      } else {
        showToast("처리할 회원 없음");
      }
    } catch(e) {
      showToast("실패: " + e.message, "err");
      console.error("[MIGRATION] 실패:", e);
    }
    setMigrating(false);
  }

  async function handleAddMember(d) {
    // survey 데이터 → bodyData.goal + bodyData.records 자동 연동 (회원 등록 시 한 번만)
    setLoading(true);
    try {
      const saved = await addMember(d);
      const sv = d.survey || {};
      if (sv && (sv.weight || sv.height || sv.purposes?.length || sv.priorityGoal)) {
        const memberId = saved?.id || d.id;
        if (memberId) {
          const autoGoal = {
            currentWeight: sv.weight || "",
            goalType: sv.purposes?.includes("체지방 감량") ? "diet"
                    : sv.purposes?.includes("근력 증가")  ? "strength"
                    : sv.purposes?.includes("벌크업")     ? "bulk"
                    : sv.purposes?.includes("체형 교정")  ? "posture"
                    : sv.purposes?.includes("재활")       ? "rehab"
                    : "",
            sleepHours:    sv.sleepHours    || "",
            stressLevel:   sv.stressLevel   || 3,
            activityLevel: sv.actLv         || sv.activityLevel || "",
            mealsPerDay:   sv.mealsPerDay   || "",
            cardioFreq:    sv.cardioFreq    || "",
            hasPain:       sv.hasPain       || false,
            height:        sv.height        || "",
            age:           sv.age           || "",
            gender:        sv.gender        || "",
          };
          // 체중이 있으면 bodyData.records에 초기 레코드 생성 (그래프/대시보드 연동)
          const autoRecords = sv.weight ? [{
            id: "r_init_" + memberId,
            date: d.startDate || new Date().toISOString().split("T")[0],
            weight: sv.weight,
            bodyFat: null,
            muscleMass: null,
            memo: "등록 시 입력 체중",
          }] : [];
          try {
            await saveBodyCheck(memberId, { goal: autoGoal, records: autoRecords });
          } catch(e) { console.warn("bodyCheck 자동 연동 실패:", e); }
        }
      }
      showToast("회원 등록 완료 ✓"); setMembers(await getMembers()); setScreen("members");
    }
    catch(e) { showToast(e.message, "err"); }
    finally { setLoading(false); }
  }

  // 테스트 회원 빠른 생성 — docs/member-app-test-accounts.md 참고
  // 실제 회원 온보딩(설문/자동목표연동)과 완전히 분리된 최소 필드만 생성한다.
  async function handleAddTestMember(preset) {
    const email = preset.email.trim().toLowerCase();
    if (members.some(m => (m.email||"").trim().toLowerCase() === email)) {
      showToast("이미 같은 이메일의 회원이 있습니다.", "err");
      return;
    }
    setLoading(true);
    try {
      await addMember({ name: preset.name, email, status: preset.status, isTestMember: true });
      showToast(`${preset.name} 생성 완료 · 상세에서 회원앱 초대를 진행하세요.`);
      setMembers(await getMembers());
    } catch(e) { showToast(e.message, "err"); }
    finally { setLoading(false); }
  }

  async function handleUpdateMember(d) {
    setLoading(true);
    try {
      await updateMember(member.id, d);
      // private 필드(memo, ticketInfo)는 memberPrivateData 상태로 관리
      const { memo, ticketInfo, ...publicD } = d;
      const u = {...member, ...publicD};
      setMember(u);
      setMemberPrivateData(prev => ({
        ...(prev || {}),
        ...('memo' in d && { memo: memo ?? "" }),
        ...('ticketInfo' in d && { ticketInfo: ticketInfo ?? "" }),
      }));
      // survey.weight 수정 시 bodyData.goal.currentWeight 동기화
      const sv = d.survey || {};
      if (sv.weight && bodyData) {
        try {
          const updatedGoal = { ...bodyData.goal, currentWeight: sv.weight };
          await saveBodyCheck(member.id, { ...bodyData, goal: updatedGoal });
          setBodyData(prev => ({ ...prev, goal: updatedGoal }));
        } catch(e) { console.warn("bodyCheck goal 동기화 실패:", e); }
      }
      showToast("수정 완료 ✓");
      setScreen("hub");
      setSessions(await getSessions(u.id));
    } catch(e) { showToast(e.message, "err"); }
    finally { setLoading(false); }
  }

  // 회원 상태 변경 (active | paused | ended)
  async function handleStatusChange(id, newStatus) {
    const labels = { active:"진행중", paused:"휴식중", ended:"종료" };
    const msg = newStatus === "ended"
      ? `종료 처리하시겠습니까?\n수업 기록은 유지됩니다.`
      : `${labels[newStatus]}으로 변경하시겠습니까?`;
    if (!window.confirm(msg)) return;
    try {
      const patch = { status: newStatus };
      if (newStatus === "ended")  patch.endedAt = new Date().toISOString().split("T")[0];
      if (newStatus === "active") patch.endedAt = null;
      await updateMember(id, patch);
      setMembers(prev => prev.map(m => m.id === id ? {...m, ...patch} : m));
      showToast(`${labels[newStatus]} 처리 완료 ✓`);
    } catch(e) { showToast(e.message, "err"); }
  }

