  async function handleSendPairSession(aSession) {
    // 나눠서 기록: A 2:1 세션에서 A/B 개인 수업일지 생성 (회원앱 공개는 각 일지에서 별도 전송)
    if (!aSession?.id || !aSession?.memberBId) {
      showToast("B 회원 정보가 없습니다", "err");
      return;
    }
    const bMember = members.find(m => m.id === aSession.memberBId);
    if (!bMember) { showToast("B 회원을 찾을 수 없습니다", "err"); return; }
    setLoading(true);
    try {
      const bSessions = await getSessions(bMember.id);
      const bSessionNo = bSessions.length > 0
        ? Number(bSessions[bSessions.length - 1].sessionNo || 0) + 1 : 1;
      const bExercises = aSession.memberBExercises || [];
      const bSessionData = {
        memberId: bMember.id,
        memberName: bMember.name,
        date: aSession.date,
        sessionNo: bSessionNo,
        sessionType: "2:1",
        linkedMemberId: member?.id,
        pairMemberId: member?.id,
        pairSessionId: aSession.id,
        exercises: bExercises,
        trainerComment: aSession.memberBComment || "",
        totalVolume: bExercises.reduce((s, e) => s + exVol(e), 0),
        intensity: aSession.intensity,
        condition: aSession.condition,
        selectedTypes: aSession.selectedTypes,
        type: aSession.type,
        isPublished: false,
        status: "draft",
      };
      await sendPairSession(member?.id, aSession.id, bMember.id, bSessionData);
      await refreshSessionsForMember(member.id);
      const bNewSessions = await getSessions(bMember.id);
      setSessionsMap(prev => ({ ...prev, [bMember.id]: bNewSessions }));
      showToast(`${bMember.name} 기록 전송 완료 ✓`);
    } catch(e) {
      showToast("전송 실패: " + e.message, "err");
    } finally {
      setLoading(false);
    }
  }
  async function handleSaveSession(d) {
    console.log("[TEO GYM] handleSaveSession — memberId:", member?.id, "data:", d?.sessionNo);
    setLoading(true);
    try {
      const now = new Date().toISOString();
      const payload = { ...d, updatedAt: now };
      if (editSess?.id) {
        await updateSession(member.id, editSess.id, payload);
        showToast("수업 수정 완료 ✓");
      } else {
        await addSession(member.id, { ...payload, createdAt: now });
        showToast("수업 저장 완료 ✓");
      }
      setEditSess(null);
      const newSessions = await getSessions(member.id);
      setSessions(newSessions);
      setSessionsMap(prev => ({...prev, [member.id]: newSessions}));
      const todayStr = new Date().toISOString().split("T")[0];
      const sorted   = [...newSessions].sort((a,b)=>(b.date||"").localeCompare(a.date||""));
      const last     = sorted[0];
      // 오늘 수업 여부 재계산 (날짜가 변경될 수 있으므로 반드시 갱신)
      const hasTodaySession = newSessions.some(s => s.date === todayStr);
      if (last && member.id) {
        const lastParts = (last.exercises||[])
          .map(e=>e.muscleTop).filter(Boolean)
          .filter((v,i,a)=>a.indexOf(v)===i).slice(0,3);
        try {
          await updateMember(member.id, {
            lastSessionDate:  last.date || "",
            lastSessionParts: lastParts,
            lastSessionNo:    last.sessionNo || "",
          });
          setMembers(prev => prev.map(m => m.id === member.id
            ? { ...m,
                lastSessionDate:  last.date || "",
                lastSessionParts: lastParts,
                lastSessionNo:    last.sessionNo || "",
                _todaySession:    hasTodaySession, // 오늘 수업 배지 즉시 갱신
              }
            : m
          ));
        } catch(e) { console.warn("[TEO GYM] lastSession 업데이트 실패:", e.message); }
      } else {
        // 세션이 없거나 last가 없을 때도 todaySession 갱신
        setMembers(prev => prev.map(m => m.id === member.id
          ? { ...m, _todaySession: hasTodaySession }
          : m
        ));
      }

      // ── 체중 양방향 동기화: 수업 체중 → 바디체크 records ───────────────
      const sessWeight = d.bodyWeight ? String(d.bodyWeight).trim() : "";
      const sessDate   = d.date || "";
      if (sessWeight && sessDate && parseFloat(sessWeight) > 0) {
        try {
          const currentBD = bodyData || {};
          const existingRecords = currentBD.records || [];
          const sameDateRec = existingRecords.find(r => r.date === sessDate);
          let updatedRecords;
          if (sameDateRec) {
            // 같은 날짜 기록이 있으면 체중만 업데이트
            updatedRecords = existingRecords.map(r =>
              r.date === sessDate ? {...r, weight: sessWeight, updatedAt: new Date().toISOString()} : r
            );
          } else {
            // 없으면 새 레코드 추가
            updatedRecords = [
              ...existingRecords,
              { id:"r"+Date.now(), date:sessDate, weight:sessWeight, updatedAt: new Date().toISOString() }
            ];
          }
          const newBD = { ...currentBD, records: updatedRecords };
          const saved = await saveBodyCheck(member.id, newBD);
          setBodyData(saved || newBD);
        } catch(e) { console.warn("[TEO GYM] 체중 바디체크 동기화 실패:", e.message); }
      }

      setScreen("hub");
    } catch(e) { showToast(e.message, "err"); }
    finally { setLoading(false); }
  }

