// ── 의료 바디차트 메인 컴포넌트 ─────────────────
function MuscleBodySVG({ muscles, bodyMap, onClickMuscle, view, mode }) {
  const tightList = muscles.filter(m => bodyMap[m.id] === "tight").map(m => m.label);
  const weakList  = muscles.filter(m => bodyMap[m.id] === "weak").map(m => m.label);

  return (
    <div style={{width:"100%", maxWidth:280, margin:"0 auto"}}>
      {/* 모드 안내 */}
      <div style={{
        textAlign:"center", marginBottom:8,
        padding:"5px 10px", borderRadius:6,
        background: mode==="tight" ? "#fef2f2" : "#eff6ff",
        border: "1px solid " + (mode==="tight" ? "#fecaca" : "#bfdbfe"),
        fontSize:11, color: mode==="tight" ? "#dc2626" : "#2563eb", fontWeight:700
      }}>
        {mode==="tight" ? "🔴 타이트 모드 — 근육을 터치하세요" : "🔵 기능저하 모드 — 근육을 터치하세요"}
      </div>

      {/* 바디차트 */}
      <div style={{
        background:"#ffffff", borderRadius:10,
        border:"1.5px solid #d1d5db",
        boxShadow:"0 1px 6px rgba(0,0,0,.08)",
        overflow:"hidden"
      }}>
        <svg viewBox="0 0 200 520" style={{width:"100%", display:"block"}}
          xmlns="http://www.w3.org/2000/svg">
          {/* 흰 배경 */}
          <rect x="0" y="0" width="200" height="520" fill="white"/>
          {/* 의료 차트 스타일 인체 도면 */}
          <BodyChart view={view} />
          {/* 투명 클릭 영역 — 선택 시만 색상 */}
          {muscles.map(m => {
            const status = bodyMap[m.id];
            const cfg    = status ? BODY_STATUS[status] : null;
            return (
              <path
                key={m.id}
                d={m.d}
                fill={status ? cfg.fill : "transparent"}
                stroke={status ? cfg.color : "transparent"}
                strokeWidth={status ? 1.5 : 0}
                style={{cursor:"pointer", transition:"fill .12s"}}
                onClick={() => onClickMuscle(m.id)}
              />
            );
          })}
        </svg>
        {/* 뷰 레이블 */}
        <div style={{
          textAlign:"center", padding:"5px 0",
          background:"#f9fafb", borderTop:"1px solid #e5e7eb",
          fontSize:9, color:"#9ca3af",
          fontFamily:"monospace", letterSpacing:".12em", fontWeight:600
        }}>
          {view === "front" ? "ANTERIOR  VIEW" : "POSTERIOR  VIEW"}
        </div>
      </div>

      {/* 선택 결과 목록 */}
      {(tightList.length > 0 || weakList.length > 0) && (
        <div style={{
          marginTop:8, padding:"8px 12px",
          background:"#f9fafb", borderRadius:8,
          border:"1px solid #e5e7eb", lineHeight:1.8
        }}>
          {tightList.length > 0 && (
            <div style={{fontSize:11}}>
              <span style={{color:"#dc2626",fontWeight:700}}>🔴 과긴장: </span>
              <span style={{color:"#374151"}}>{tightList.join("  ·  ")}</span>
            </div>
          )}
          {weakList.length > 0 && (
            <div style={{fontSize:11}}>
              <span style={{color:"#2563eb",fontWeight:700}}>🔵 기능저하: </span>
              <span style={{color:"#374151"}}>{weakList.join("  ·  ")}</span>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

// ── 통증 메모 AI 자동 파싱 ─────────────────────────────────────────────
function parsePainMemo(text) {
  if (!text || text.trim().length < 2) return null;
  const t = text.toLowerCase();
  const result = {};
  const partMap = [
    ["목","목"],["상부승모","상부승모"],["견갑","견갑"],["어깨","어깨"],
    ["팔꿈치","팔꿈치"],["손목","손목"],["흉추","흉추"],
    ["허리","허리"],["고관절","고관절"],["둔근","둔근"],
    ["햄스트링","햄스트링"],["무릎","무릎"],["종아리","종아리"],
    ["발목","발목"],["발바닥","발바닥"],
  ];
  for (const [k,v] of partMap) { if (t.includes(k)) { result.part = v; break; } }
  if (t.includes("왼쪽")||t.includes("좌측")||t.includes("left")) result.side="왼쪽";
  else if (t.includes("오른쪽")||t.includes("우측")||t.includes("right")) result.side="오른쪽";
  else if (t.includes("양측")||t.includes("양쪽")) result.side="양측";
  const vasMatch = t.match(/vas\s*(\d+)|(\d+)\s*vas|통증\s*(\d+)|(\d+)점|강도\s*(\d+)/);
  if (vasMatch) {
    const v = parseInt(vasMatch[1]||vasMatch[2]||vasMatch[3]||vasMatch[4]||vasMatch[5]);
    if (v>=0 && v<=10) result.vas = v;
  }
  if (!result.vas) {
    const numEnd = t.match(/(\d+)\s*$/);
    if (numEnd) { const v=parseInt(numEnd[1]); if(v>=0&&v<=10) result.vas=v; }
  }
  const sitMap = [
    ["앉","오래 앉을 때"],["서있","오래 서있을 때"],["걷","걷기"],
    ["계단","계단"],["스쿼트","스쿼트"],["런지","런지"],
    ["벤치프레스","벤치프레스"],["팔 들","팔 들기"],
    ["운동 중","운동 중"],["운동 후","운동 후"],["아침","아침 기상 시"],
    ["운전","오래 운전할 때"],
  ];
  for (const [k,v] of sitMap) { if (t.includes(k)) { result.situation=v; break; } }
  return Object.keys(result).length > 0 ? result : null;
}

